me, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '服务到位！非常好', '服务到位！非常好', '2023-10-01', 5, '[''前台服务'', ''客房服务'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0235112000caqdofeAFBE_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234112000caq2au70D78_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '装修高端大气，设施先进完善，viria的服务态度超好，比预想中的好很多～强烈推荐', '装修高端大气，设施先进完善，viria的服务态度超好，比预想中的好很多～强烈推荐粤韵套房，大小合适，景观很棒！', '2023-06-26', 5, '[''房间设施'', ''景观/朝向'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0233412000bi8vuohFBD7_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231612000bi8s3hb657D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236512000bi8ytxb86E2_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230p12000bi8z0g2AA3B_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '第一次假期出游选择花园酒店，确实很惊艳，小朋友很喜欢。因行程比较赶，都来不及细细', '第一次假期出游选择花园酒店，确实很惊艳，小朋友很喜欢。因行程比较赶，都来不及细细品味这家老牌酒店，荔湾亭的一元一碗豆腐花让人印象深刻。前台阿KEN服务很友好，让人如沐春风，下次还会来。', '2023-10-04', 5, '[''前台服务'', ''餐饮设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0232312000cbqh7emF3B8_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230212000cbqlihv0C86_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232s12000cbqifcsE35E_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '40年历史的酒店，保养的很好，房间挺舒服的，酒店的餐厅菜品一般，尤其是那个米其林', '40年历史的酒店，保养的很好，房间挺舒服的，酒店的餐厅菜品一般，尤其是那个米其林餐厅又油又咸。
行政酒廊外面挨着花园，有瀑布环廊，环境真是不错。很舒适，这个酒店的设计师是贝聿铭先生，所以花园采光的玻璃环廊设计是他风格。酒店服务也不错??，个人认为体验感比天河希尔顿好太多', '2023-04-18', 5, '[''整体满意度'', ''餐饮设施'', ''公共设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0234712000aziqg4v11D7_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231c12000azilegrA560_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232u12000azihe2wD1A4_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231412000azii1ac057C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236912000aziril582C5_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231n12000azigggo5399_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235b12000aziwlmv02CC_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236w12000aziqpozCE10_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236712000aziwlmx9C1D_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '非常大气的酒店 逛了花园又参观花园酒店博物馆 客人非常多尤其外国客人 早餐质量也', '非常大气的酒店 逛了花园又参观花园酒店博物馆 客人非常多尤其外国客人 早餐质量也非常棒 建议西式早餐 环境好 品众多', '2023-06-26', 5, '[''餐饮设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0235c12000bi5pg6yFFE2_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234q12000bi5n27cB1D5_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231s12000bi5q7gf00F8_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233x12000bi5vzk5FC0C_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '大堂很气派，能感受到员工的热情，房间不算很大但备品赠饮各方面都有奢华酒店的水准', '大堂很气派，能感受到员工的热情，房间不算很大但备品赠饮各方面都有奢华酒店的水准', '2023-07-25', 5, '[''整体满意度'', ''前台服务'', ''房间设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0232612000bqn9bt595F5_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '非常舒适的入住，酒店位置也非常方便', '非常舒适的入住，酒店位置也非常方便', '2023-09-06', 5, '[''整体满意度'', ''交通便利性'']', '["[ \"https://dimg04.c-ctrip.com/images/0235r2215g9caygc0D123_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232p2224wcph17ht757E_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '挺好的前台小姐姐也免费升了房开心～', '挺好的前台小姐姐也免费升了房开心～', '2023-09-06', 5, '[''前台服务'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0235412000c2yeq2j684F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236e12000c2y8r7zCDFF_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232v12000c2ybz1v8A9E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233m12000c2yj33q8CA8_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店大堂很气派，服务员很热情，环境很漂亮，房间不大，家具有些陈旧了。五一节入住还', '酒店大堂很气派，服务员很热情，环境很漂亮，房间不大，家具有些陈旧了。五一节入住还收到??。因为不含早餐，也不知道早餐质量如何。但是开在酒店的餐厅却不是太友好价格贵点荔浦不推荐。', '2023-05-22', 4, '[''房间设施'', ''餐饮设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0234p12000b9llnvc58B7_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230812000b9m4oa14B15_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230912000b9lfm3v0F83_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230m12000b9lwpni8203_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232y12000b9lmde0CEDC_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233312000b9m3yrbECE1_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230f12000b9lqs7k1013_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235i12000b9l9rixB3D7_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店前台工作人员小胡热情接待，给人宾至如归的感觉，还给我们免费升级了房间，非常开', '酒店前台工作人员小胡热情接待，给人宾至如归的感觉，还给我们免费升级了房间，非常开心。晚上还送了小甜品，精致好吃。下次有机会还会选择花园酒店。', '2024-06-20', 5, '[''前台服务'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0236b12000ej5s3nq153E_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店服务非常好，出行交通方便，推荐', '酒店服务非常好，出行交通方便，推荐', '2023-09-13', 5, '[''前台服务'', ''交通便利性'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0235m12000c4ao9guBCB0_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236412000c4bre0r009D_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '设施：大堂跟气派，工作人员很友好', '设施：大堂跟气派，工作人员很友好
卫生：卫生很干净
环境：酒店大堂环境很好，外面施工比较吵
服务：服务好，态度好
唯一不好的就是客房太小，设计很旧，感觉像三星级，跟外面大堂不匹配', '2023-05-06', 4, '[''房间设施'', ''安静程度'', ''卫生状况'']', '["[ \"https://dimg04.c-ctrip.com/images/0230f12000b62xhv28E3E_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '房间干净，服务好，米其林餐厅味道很好，出行方便，免费停车，地铁口在酒店门口，后花', '房间干净，服务好，米其林餐厅味道很好，出行方便，免费停车，地铁口在酒店门口，后花园景色不错，酒店整体感觉都很好，', '2023-06-09', 5, '[''交通便利性'', ''卫生状况'', ''餐饮设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0235312000bdpxw19F162_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234912000bdpsd3yAE13_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230u12000bdpw2fw95D2_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230912000bdpyf1vF5FF_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232i12000bdpyg21486E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230j12000bdpygyg5887_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232f12000bdpt6x29C9C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234a12000bdpxlc929FD_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232d12000bdpwj7m3AE4_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店太让人震感惊艳了！打假期间，服务不打折，热情周到主动！并且还为我们房间升级为', '酒店太让人震感惊艳了！打假期间，服务不打折，热情周到主动！并且还为我们房间升级为套房！服务特别贴心！早餐很丰富，各种风味品类，餐厅都有三个，随便任由自己选择！广州花园酒店代表着广州经济的飞速发展与经济地位！花园酒店不仅有沉淀，地理位置还非常方便，出门就是地铁，无论到那里景区都是最方便的选择！', '2023-05-01', 5, '[''前台服务'', ''餐饮设施'', ''交通便利性'']', '["[ \"https://dimg04.c-ctrip.com/images/0230m12000b4lf31p1A52_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232j12000b4lq19cE256_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231p12000b4lnm982E1D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236j12000b4ltzv149F1_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '半夜五点，突然被暴力的踢门声吓醒，还一脸蒙蔽，然后还继续踢，吓**，老公通过猫眼', '半夜五点，突然被暴力的踢门声吓醒，还一脸蒙蔽，然后还继续踢，吓**，老公通过猫眼看是有个外国人在踢对面的房门，还一直在门口吵，我还以为是踢我们的房门赶紧用座机打电话客服中心，居然没人听。后来用手机搜电话打通让人上来处理，**的吓**还带着孩子呢！', '2023-04-12', 3, '[''安静程度'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0235t12000ax261oyC33E_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '金玉其外 败絮其中。4.6的分都高了。', '金玉其外 败絮其中。4.6的分都高了。
真诚的建议所有想来体验五星白金酒店的旅客不要入住花园酒店。来大厅，四楼博物馆（免费的对外开放登记就能进入），还有瀑布后花园（入口在瀑布餐厅和前台中间在一个酒柜那里对外开放不用刷卡）打卡即可。 餐厅也都是对外开放的。

真心不用花一千多块钱大老远跑来住又破又脏的房间。

1 酒店未提前告知最近有大面积施工??，酒店后面全部是工地，每天早上7点半准时开工晚上8点半回来噪声还非常大。（详见两个视频第一个工地??第二个是在床上录的）想象一下这个噪音。心脏脆弱的人会得心脏病的声音非常大。

2 刚入住就发现房间地板上有很多头发，赶紧联系客房部。大概十分钟后服务生来吸了地。卫生一塌糊涂有被浴室排水槽里的头发和棉签恶心??烧水壶上还有白乎乎的水垢可以扣下来的那种。桌子上也有不明白色粉末。

3 强烈怀疑说是装修过了的，有污渍的音响，老化的浴室，破旧的天花板，破了用透明胶带粘住的桌面，有污点的沙发，和看上去快要退休的椅子??。

4 头一回碰见在入住时就被要求离店打五星好评？！！！我房间都没进呢就要我打五星好评？！！！目的性太强，入住时我说小羊很可爱想买一只前台说离店时可以送我一只，但是！必须离店时出示带有她名字的五星好评！！！才能送我！！入住时说这些令人很不舒服。 （就这水准五星好评不可能的）最后离店时前台说小羊没有了送积木（从来就没打算要酒店送小羊）。不用了真的太糟糕了。

5 找了经理投诉态度很好，经理邀请下次入住时升级房间。婉拒了，没有下次了。

6 可以考虑用本地品牌的茶叶，毕竟主打岭南风用英国????茶不伦不类。外宾多更要让人家尝尝本地茶叶啊？！自己说的要打造民族品牌奢华酒店。

后悔没住凯宾斯基了差不多的价格人家还新还没施工也有高楼层景色，走到花园五分钟打个卡多好。', '2023-03-13', 2, '[''房间设施'', ''卫生状况'', ''安静程度'']', '["[ \"https://dimg04.c-ctrip.com/images/0200u12000arnzgtm6D66_W_350_350_R5_Q70.jpg?proc=autoorient\", \"https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png\", \"https://dimg04.c-ctrip.com/images/0206s12000arnzmwg4E1C_W_350_350_R5_Q70.jpg?proc=autoorient\", \"https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png\", \"https://dimg04.c-ctrip.com/images/0235j12000arnrhyl79B6_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233e12000arntmxxD29F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231g12000arnknrg4751_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234b12000arnmps874B8_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235t12000arnjy5qEC79_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235h12000arnsb661A9A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232z12000arnmnq40107_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232612000arnqcle8E28_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232012000arnqloi5D6E_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店整体很好，服务很热情，负责。又续住了一晚', '酒店整体很好，服务很热情，负责。又续住了一晚', '2023-08-19', 5, '[''整体满意度'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0231e12000bycp67zCFD0_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233d12000byctgl2B6D3_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '前台接待亲切友好，住宿环境舒适，房间干净卫生，酒店自助早餐丰富，交通便利配套足，', '前台接待亲切友好，住宿环境舒适，房间干净卫生，酒店自助早餐丰富，交通便利配套足，性价比很高，下次再入住，值得推荐！', '2023-06-17', 5, '[''整体满意度'', ''前台服务'', ''性价比'']', '["[ \"https://dimg04.c-ctrip.com/images/0236a2215fddosbm8E3D1_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/023492215fddosbm9C419_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231u2224vgquvahs4ECC_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232b2224vgquvi7k1C44_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '广州花园酒店的发展，见证了中国改革开放后的文化，经济，政治变化，成立于1984年', '广州花园酒店的发展，见证了中国改革开放后的文化，经济，政治变化，成立于1984年，由邓小平题字，是改革开放后第一家引进外资的酒店，酒店大堂简直是太美了，背景墙给我们带入了曹雪芹笔下的《红楼梦》场景和水乡风貌，里面有一家博物馆，让我们了解到很多酒店业的历史和文化，后花园里边非常精彩只入住了两天，感觉恋恋不舍，所有地方都太喜欢了！我认为是到广州住酒店的首选！', '2023-04-10', 5, '[''整体满意度'', ''公共设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0200c12000awgtdm1293C_W_350_350_R5_Q70.jpg?proc=autoorient\", \"https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png\", \"https://dimg04.c-ctrip.com/images/0201912000awgtdz4FFDD_W_350_350_R5_Q70.jpg?proc=autoorient\", \"https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png\", \"https://dimg04.c-ctrip.com/images/0204w12000awgte0p2243_W_350_350_R5_Q70.jpg?proc=autoorient\", \"https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png\", \"https://dimg04.c-ctrip.com/images/0234012000aw4ytzrA66E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232912000aw4waj178CB_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233312000aw4to7eC242_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230i12000aw4wls60BC0_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235j12000awgs08kF03A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235s12000aw4ounj9F85_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233n12000awg4n8x3557_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '入住广州花园酒店是我最满意的。地理位置优越、出入方便；环境优美；酒店里的花园、瀑', '入住广州花园酒店是我最满意的。地理位置优越、出入方便；环境优美；酒店里的花园、瀑布餐厅给我惊艳到了。前台小哥（没记下他的名字，不好意思）行政酒廊的凯琳-耐心、仔细、服务周到；瀑布餐厅的帅哥靓女们各个都服务周到细致。下次去广州我还会入住花园酒店??花园酒店-我喜欢??', '2023-08-04', 5, '[''整体满意度'', ''前台服务'', ''周边配套'']', '["[ \"https://dimg04.c-ctrip.com/images/0234012000btps735F080_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230z12000btpsctc5D83_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0237112000btpskbq7034_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236d12000btpyezxB056_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235312000btpyd33DDB9_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '前台服务很好，3楼早茶环境很好。', '前台服务很好，3楼早茶环境很好。', '2023-08-30', 5, '[''前台服务'', ''餐饮设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0231z12000c1a1ur4B604_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '很好很好很好很好很好很好很好很好很好很好很好很好很好很好很好很好很好很好很好很好', '很好很好很好很好很好很好很好很好很好很好很好很好很好很好很好很好很好很好很好很好很好很好很好很好很好', '2023-06-23', 5, '[''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0235d12000bhga5jo40ED_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234112000bhg4u02EE12_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230q12000bhg7ff7B6EF_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '这是一家充满历史，环境优美，体验舒适的酒店，性价比很高！花园酒店实至名归，仿佛置', '这是一家充满历史，环境优美，体验舒适的酒店，性价比很高！花园酒店实至名归，仿佛置身一座美丽的后花园中。酒店除了房间面积小了点，其他都很好。餐厅泳池健身房也都不错，桃园餐厅稍微有点贵。附近有很多老字号，点都德、陶陶居都不错，尤其是点都德好吃不贵！', '2023-04-17', 5, '[''整体满意度'', ''性价比'', ''周边配套'']', '["[ \"https://dimg04.c-ctrip.com/images/0236y12000ayyog6qB1A2_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233u12000ayyrd1f0D39_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233p12000ayygth3E88A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231q12000ayxvhyfA2C0_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233t12000ayyluqj0ED1_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234712000ayyut5x4C68_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235212000ayysfld8308_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '非常有历史韵味的酒店，大堂很美，但是房间内部设施偏老旧。位置在老城区内算比较方便', '非常有历史韵味的酒店，大堂很美，但是房间内部设施偏老旧。位置在老城区内算比较方便的，离地铁近，旁边也有商场还有几家比较有名的粤菜馆。整体服务不错，因带孩子还给帮忙延迟退房了。但是人真多，办理入住，吃早饭 都要排队。', '2023-04-15', 4, '[''房间设施'', ''交通便利性'', ''周边配套'']', '["[ \"https://dimg04.c-ctrip.com/images/0230g12000ayg9jbl5DCA_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '我们住的楼层外面在修路，没什么好看的，但是没有很吵，对我们没什么影响，入住之前就', '我们住的楼层外面在修路，没什么好看的，但是没有很吵，对我们没什么影响，入住之前就已经提醒了，市政工程也能理解，办理入住的时候给小朋友提供了小饼干，服务很好，后花园很美，自己带的面包，小朋友去喂了鱼，装修风格很有岭南特色，还特意去参观了四楼的酒店博物馆，小朋友还很喜欢这里，下次还会选择入住这里。', '2023-04-09', 4, '[''整体满意度'', ''前台服务'', ''景观/朝向'']', '["[ \"https://dimg04.c-ctrip.com/images/0233q12000aw2d4uwBFF5_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '环境不错，地铁施工有点吵，其它都不错', '环境不错，地铁施工有点吵，其它都不错', '2023-08-26', 5, '[''安静程度'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0230e12000c0dxpwv29BB_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230312000c0dxls94778_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236l12000c0dxiy6CE19_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233m12000c0dxno92A5A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235e12000c0dxnoc8BA2_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', 'Vivia小姐姐服务态度特别好，还贴心的送花束。室外游泳池挺不错的，旁边是大花园', 'Vivia小姐姐服务态度特别好，还贴心的送花束。室外游泳池挺不错的，旁边是大花园还有瀑布。宾馆里有不少帅哥美女，赞??', '2023-06-12', 5, '[''前台服务'', ''公共设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0231s12000befvdz30552_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230g12000beg7z7jF7BC_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231s12000befzst22418_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店给做了升级，一切都棒棒的', '酒店给做了升级，一切都棒棒的', '2023-09-03', 5, '[''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0234m12000c23j20z1722_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231h12000c23k4ycB321_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232s12000c23gr6h04EB_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234012000c238bc5D885_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '体验很舒服，很满意！', '体验很舒服，很满意！', '2023-09-10', 5, '[''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0235j12000c3r1m2wC998_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '卫生怎能这么的差呢？', '卫生怎能这么的差呢？', '2023-09-09', 2, '[''卫生状况'']', '["[ \"https://dimg04.c-ctrip.com/images/0232a12000c3kf786D4C9_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234z12000c3kead000FB_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235a12000c3kj270AEFA_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231412000c3kd5c82717_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '一点都不值800+的价格 其他品牌四星酒店更便宜 这是更优 花园就靠着这个牌子赚', '一点都不值800+的价格 其他品牌四星酒店更便宜 这是更优 花园就靠着这个牌子赚足了人气 但是败絮其中
这个房间多说也就价值400-500 纯纯大冤种 因为太不满意想要提前离店 退换未住部分 但是经销商和酒店踢皮球 只能继续住

环境：除了房间家具设施 真的很富丽堂皇 公共区域干净整洁 气味香香的 电梯数量足 冷气足

服务：从进门开始 门口迎宾 大堂服务 客房服务 礼宾服务工作人员服务都很好 态度很友好 满足需求 很满意

设施：水压很大 洗澡舒服 & 床够大够软 睡觉很舒服
但是页面上写的2019年装修 但是地板家具很陈旧 椅子皮很老了 真的该换了上面有明显污渍
电子秤没有电的 换了新的 后又因外部道路施工噪音问题换了房间 新的房间电子秤依然没电……

卫生：桌面和椅子用纯水湿巾擦拭能明显变黄 擦拭完后再擦无变黄 说明平时清理不够
